import{_ as r,o as e,c as t,ae as i}from"./chunks/framework.CFyvOAXl.js";const p=JSON.parse('{"title":"Sharding分片技术及业界方案","description":"","frontmatter":{},"headers":[],"relativePath":"program/cpp/Sharding.md","filePath":"program/cpp/Sharding.md","lastUpdated":1615307889000}'),n={name:"program/cpp/Sharding.md"};function d(o,a,h,l,s,c){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="sharding分片技术及业界方案" tabindex="-1">Sharding分片技术及业界方案 <a class="header-anchor" href="#sharding分片技术及业界方案" aria-label="Permalink to &quot;Sharding分片技术及业界方案&quot;">​</a></h1><h2 id="定义-维基百科" tabindex="-1">定义（维基百科） <a class="header-anchor" href="#定义-维基百科" aria-label="Permalink to &quot;定义（维基百科）&quot;">​</a></h2><p>A database shard, or simply a shard, is a horizontal partition of data in a database or search engine. Each shard is held on a separate database server instance, to spread load.</p><p>数据库分片（或简称为分片）是数据库或搜索引擎中数据的<strong>水平分区</strong>。每个分片都保存在单独的数据库服务器实例上，以分散负载。</p><h2 id="sharding-方式" tabindex="-1">Sharding 方式 <a class="header-anchor" href="#sharding-方式" aria-label="Permalink to &quot;Sharding 方式&quot;">​</a></h2><ul><li>1、基于键的分片</li><li>2、基于范围的分片</li><li>3、基于目录的分片</li></ul><h2 id="分片的好处" tabindex="-1">分片的好处 <a class="header-anchor" href="#分片的好处" aria-label="Permalink to &quot;分片的好处&quot;">​</a></h2><ul><li>促进水平扩展</li><li>降低宕机风险</li></ul><h2 id="分片的缺点" tabindex="-1">分片的缺点 <a class="header-anchor" href="#分片的缺点" aria-label="Permalink to &quot;分片的缺点&quot;">​</a></h2><ul><li>数据热点问题，这种情况需要重新分片</li></ul><h2 id="业界sharding方案" tabindex="-1">业界sharding方案 <a class="header-anchor" href="#业界sharding方案" aria-label="Permalink to &quot;业界sharding方案&quot;">​</a></h2><ul><li>MongoDB</li><li>ShardingSphere <a href="https://shardingsphere.apache.org/document/current/cn/overview/" target="_blank" rel="noreferrer">https://shardingsphere.apache.org/document/current/cn/overview/</a></li><li>MySQL Proxy + HSCALE</li><li>Hibernate Shards</li><li>Spock Proxy 基于范围的sharding机制</li><li>HiveDB</li><li>PL/Proxy</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><p>[1]Shard (database architecture) <a href="https://en.wikipedia.org/wiki/Shard_(database_architecture)" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Shard_(database_architecture)</a></p><p>[2]Understanding Database Sharding <a href="https://www.digitalocean.com/community/tutorials/understanding-database-sharding" target="_blank" rel="noreferrer">https://www.digitalocean.com/community/tutorials/understanding-database-sharding</a></p><p>[3]开源数据库Sharding技术 <a href="https://developer.aliyun.com/article/530190" target="_blank" rel="noreferrer">https://developer.aliyun.com/article/530190</a></p><p>[4]MongoDB中文文档 <a href="https://www.docs4dev.com/docs/zh/mongodb/v3.6/reference/sharding.html" target="_blank" rel="noreferrer">https://www.docs4dev.com/docs/zh/mongodb/v3.6/reference/sharding.html</a></p><h2 id="图片来源" tabindex="-1">图片来源 <a class="header-anchor" href="#图片来源" aria-label="Permalink to &quot;图片来源&quot;">​</a></h2><p>[1]Understanding Database Sharding <a href="https://www.digitalocean.com/community/tutorials/understanding-database-sharding" target="_blank" rel="noreferrer">https://www.digitalocean.com/community/tutorials/understanding-database-sharding</a></p>',19)])])}const u=r(n,[["render",d]]);export{p as __pageData,u as default};
